    /**
     * Extrae el lexema de un token con formato "lexema:tipo".
     *
     * Entrada: s — String con formato "lexema:tipo" o solo lexema.
     * Salida: la parte antes de ':', o s completo si no contiene ':'.
     * Restricción: retorna s sin modificar si es null o no contiene ':'.
     */


    /**
     * Extrae el tipo de un token con formato "lexema:tipo".
     *
     * Entrada: s — String con formato "lexema:tipo", o valores especiales "error"/"vacio".
     * Salida: la parte después de ':', o s completo si no tiene ':'.
     * Restricción: retorna null si s es null; retorna s sin modificar para "error" y "vacio".
     */


    static String lexemaDe(String s) {
        if (s == null) return "";
        if (s.equals("vacio") || s.equals("error")) return s;

        int pos = s.lastIndexOf(':');
        if (pos == -1) return s;

        return s.substring(0, pos);
    }

    static String tipoDe(String s) {
        if (s == null) return "error";
        if (s.equals("vacio") || s.equals("error")) return s;

        int pos = s.lastIndexOf(':');
        if (pos == -1) return s;

        return s.substring(pos + 1);
    }

    /**
     * Cuenta el número de filas de una matriz representada como String.
     *
     * Entrada: valor — String con formato "[[a,b],[c,d]]:tipo".
     * Salida: int con la cantidad de filas (número de '[' en el contenido interno).
     * Restricción: asume formato válido; no valida estructura de la cadena.
     */
    public int obtenerCantFilas(String valor) {
        String matriz = valor.split(":")[0];
        matriz = matriz.substring(1, matriz.length() - 1);
        int filas = 0;
        for (int i = 0; i < matriz.length(); i++) {
            if (matriz.charAt(i) == '[') filas++;
        }
        return filas;
    }

    /**
     * Cuenta el número de columnas de una matriz representada como String.
     *
     * Entrada: valor — String con formato "[[a,b],[c,d]]:tipo".
     * Salida: int con la cantidad de columnas por fila.
     *         Retorna -1 si las filas tienen distinto número de columnas (matriz irregular).
     * Restricción: asume formato válido; no valida estructura de la cadena.
     */
    public int obtenerCantColumnas(String valor) {
        String matriz = valor.split(":")[0];
        matriz = matriz.substring(1, matriz.length() - 1);
        String[] filas = matriz.split("\\],\\[");
        int columnas = -1;
        for (String fila : filas) {
            fila = fila.replace("[", "").replace("]", "");
            int cantColumnas = fila.trim().isEmpty() ? 0 : fila.split(",").length;
            if (columnas == -1) {
                columnas = cantColumnas;
            } else if (columnas != cantColumnas) {
                return -1;
            }
        }
        return columnas;
    }

