    /**
     * Registra un error sintáctico con número de línea cuando está disponible.
     * Primero intenta obtener la línea desde el símbolo que causó el error;
     * si no está disponible, la consulta directamente al lexer.
     *
     * Entrada:
     *   message — descripción del error.
     *   info    — símbolo que provocó el error (puede ser null).
     * Salida: agrega el error a SYNTAX_ERRORS y lo imprime en stderr.
     * Restricción: si no se puede determinar la línea, el mensaje omite el número.
     */
    @Override
    public void report_error(String message, Object info) {
        String formatted;
        int line = -1;

        if (info instanceof Symbol) {
            Symbol symbol = (Symbol) info;
            if (symbol.left > 0) line = symbol.left;
        }

        if (line == -1) {
            try {
                java_cup.runtime.Scanner currentScanner = getScanner();
                if (currentScanner instanceof scanner.Lexer) {
                    line = ((scanner.Lexer) currentScanner).getCurrentLine();
                }
            } catch (Exception ex) { }
        }

        formatted = (line > 0)
            ? "Error sintactico en linea " + line + ": " + message
            : "Error sintactico: " + message;

        SYNTAX_ERRORS.add(formatted);
        System.err.println(formatted);
    }

